import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { authGuard, authChildGuard, authMatchGuard } from './services/auth.guard';

export const routes: Routes = [
  // ──────────────────────────────────────────────────────
  // LOGIN / PUBLIC ROUTES
  // ──────────────────────────────────────────────────────
  {
    path: 'login',
    loadChildren: () =>
      import('./auth/login/login.module').then((m) => m.LoginModule),
  },
  {
    path: 'CreatePassword',
    loadChildren: () =>
      import('./auth/create-pass/create-pass.module').then(
        (m) => m.CreatePassModule
      ),
  },
  {
    path: 'forgot-password',
    loadChildren: () =>
      import('./auth/forgot-password/forgot-password.module').then(
        (m) => m.ForgotPasswordModule
      ),
  },
  {
    path: 'createPassword2',
    loadChildren: () =>
      import('./auth/create-password/create-password.module').then(
        (m) => m.CreatePasswordModule
      ),
  },
  {
    path: 'ResetPassword',
    loadChildren: () =>
      import('./auth/reset-password/reset-password.module').then(
        (m) => m.ResetPasswordModule
      ),
  },

  // ──────────────────────────────────────────────────────
  // PROTECTED APP AREA (requires token or SSO cookie)
  // ──────────────────────────────────────────────────────
  {
    path: '',
    canActivate: [authGuard],
    canActivateChild: [authChildGuard],
    canMatch: [authMatchGuard],
    loadChildren: () =>
      import('./dashboard/dashboard.module').then((m) => m.DashboardModule),
  },

  {
    path: 'dashboard',
    canActivate: [authGuard],
    canActivateChild: [authChildGuard],
    canMatch: [authMatchGuard],
    loadChildren: () =>
      import('./dashboard/dashboard.module').then((m) => m.DashboardModule),
  },

  // ──────────────────────────────────────────────────────
  // WILDCARD / FALLBACK
  // ──────────────────────────────────────────────────────
  {
    path: '**',
    redirectTo: '',
  },
];

@NgModule({
  imports: [RouterModule.forRoot(routes, { scrollPositionRestoration: 'enabled' })],
  exports: [RouterModule],
})
export class AppRoutingModule { }
