import { inject } from '@angular/core';
import { Router, ActivatedRouteSnapshot, RouterStateSnapshot, UrlTree, CanActivateFn, CanActivateChildFn, CanMatchFn, UrlSegment, Route } from '@angular/router';
import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { Observable, throwError, of } from 'rxjs';
import { catchError, filter, map, take } from 'rxjs/operators';
import { TokenStorageService } from './token-storage.service';
import { SharedService } from './shared.service';
import { AuthService } from '../auth/services/auth.service';
import { HttpService } from './http.service';
import { environment } from 'src/environments/environment';
import { ApiUrls } from '../shared/routes/apiUrl';
import { JwtHelperService } from '@auth0/angular-jwt';

// Portal ID (for ClickPortal)
const PORTAL_ID = '9009';
const SESSION_FLAG_CLICK = `portalClick:${PORTAL_ID}`;
const SESSION_FLAG_USER = `ssoUserSaved`;

export const authGuard: CanActivateFn = (route, state) =>
  handleAuthGuard(route, state.url);
export const authChildGuard: CanActivateChildFn = (route, state) =>
  handleAuthGuard(route, state.url);
export const authMatchGuard: CanMatchFn = (route: Route, segments: UrlSegment[]) => {
  const url = '/' + segments.map(s => s.path).join('/');
  return handleAuthGuard({ queryParams: {} } as ActivatedRouteSnapshot, url);
};

function handleAuthGuard(
  route: ActivatedRouteSnapshot,
  url: string
): Observable<boolean | UrlTree> | boolean | UrlTree {
  const router = inject(Router);
  const http = inject(HttpClient);
  const sharedService = inject(SharedService);
  const httpService = inject(HttpService);
  const authService = inject(AuthService);
  const tokenStore = inject(TokenStorageService);
  const jwtHelper = inject(JwtHelperService);

  const urlToken = route.queryParams['token'];
  const localToken = sharedService.getToken;
  const ssoAccess = tokenStore.ssoAccessToken;
  const ssoRefresh = tokenStore.ssoRefreshToken;
  const inSSOMode = tokenStore.isSingleSignOnMode;

  const getAccessEndpoint = `${environment.masterBaseUrl.replace(/\/+$/, '')}/${ApiUrls.User.GetAccess.replace(/^\/+/, '')}`;

  // 1️⃣ Bypass dev mode
  if (environment.bypassAuth && environment.staticAuth?.token) {
    console.log('%c[DEV BYPASS]', 'color:orange;', 'Local auth bypassed.');
    return true;
  }

  // 2️⃣ If ?token= provided → normal login flow (portal redirect)
  if (urlToken) {
    localStorage.setItem('redirectUrl', route.queryParams['redirectUrl'] || '/');
    tokenStore.saveToken(urlToken);
    try {
      const payload = jwtHelper.decodeToken(urlToken);
      tokenStore.saveUser(payload);
    } catch {
      router.navigate(['/unauthorized']);
      return false;
    }
    return validateAccessToken(tokenStore, http, authService, router, getAccessEndpoint);
  }

  // 3️⃣ If SSO cookies exist → auto validate
  if (inSSOMode && ssoAccess && ssoRefresh) {
    ensureSsoUserSaved(tokenStore, jwtHelper);
    ensurePortalClickIfSso(tokenStore, httpService);
    return validateAccessToken(tokenStore, http, authService, router, getAccessEndpoint);
  }

  // 4️⃣ Normal local token
  if (localToken && localToken !== 'undefined') {
    return true;
  }

  // 5️⃣ No token → redirect
  return redirectToPortal(router);
}

// ─────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────
function validateAccessToken(
  tokenStore: TokenStorageService,
  http: HttpClient,
  authService: AuthService,
  router: Router,
  getAccessEndpoint: string
): Observable<boolean> {
  const token = tokenStore.ssoAccessToken || tokenStore.token;
  if (!token) {
    return of(false);
  }

  return http.post(getAccessEndpoint, { token }).pipe(
    map((res: any) => {
      if (res?.Status === false) {
        throw new HttpErrorResponse({ error: res, status: 401 });
      }
      return true;
    }),
    catchError(err => {
      if (err instanceof HttpErrorResponse && tokenStore.isSingleSignOnMode) {
        const refreshToken = tokenStore.ssoRefreshToken;
        if (!refreshToken) {
          return of(false);
        }
        return refreshAndRetry(authService, tokenStore, router);
      }
      return throwError(() => err);
    })
  );
}

function refreshAndRetry(
  authService: AuthService,
  tokenStore: TokenStorageService,
  router: Router
): Observable<boolean> {
  const { isRefreshing, tokenSubject } = authService.getRefreshState();
  if (!isRefreshing) {
    const refreshToken = tokenStore.ssoRefreshToken!;
    return authService.refreshToken(refreshToken).pipe(
      map(() => true),
      catchError(() => {
        router.navigate(['/login']);
        return of(false);
      })
    );
  }

  return tokenSubject.pipe(
    filter(t => t !== null),
    take(1),
    map(() => true)
  );
}

function ensureSsoUserSaved(tokenStore: TokenStorageService, jwtHelper: JwtHelperService) {
  if (sessionStorage.getItem(SESSION_FLAG_USER) === '1') return;

  const token = tokenStore.ssoAccessToken;
  if (!token) return;

  try {
    const decoded: any = jwtHelper.decodeToken(token);
    const id = decoded.nameid || decoded.UserID || decoded.sub || null;
    tokenStore.saveUser({
      nameid: id,
      UserID: id,
      fullName: decoded.unique_name ?? decoded.name ?? '',
    });
    sessionStorage.setItem(SESSION_FLAG_USER, '1');
  } catch {}
}

function ensurePortalClickIfSso(tokenStore: TokenStorageService, httpService: HttpService) {
  if (sessionStorage.getItem(SESSION_FLAG_CLICK) === '1') return;

  const userId = tokenStore.currentUserId;
  if (!userId) return;

  const fd = new FormData();
  fd.append('UserID', String(userId));
  fd.append('PortalID', PORTAL_ID);
  httpService.post(ApiUrls.User.ClickPortal, fd, 'master').subscribe({
    next: () => sessionStorage.setItem(SESSION_FLAG_CLICK, '1'),
  });
}

function redirectToPortal(router: Router): UrlTree | boolean {
  const host = window.location.host;
  if (host.includes('dxpos.markaziaapis.com')) {
    window.location.href = 'https://portal.markaziahub.com';
  } else if (host.includes('dxtestpos.markaziaapis.com')) {
    window.location.href = 'https://dxtestportal.markaziahub.com';
  } else if (host.includes('dxdevpos.markaziaapis.com')) {
    window.location.href = 'https://dxdevportal.markaziahub.com';
  } else {
    router.navigate(['/login']);
  }
  return false;
}
